UPDATE `orders`
SET status = #{status}
WHERE id IN (
    SELECT orders_id FROM order_approval
    WHERE approval_id = #{approvalId}
)

UPDATE `return`
SET status = #{status}
WHERE id IN (
    SELECT return_id FROM return_approval
    WHERE approval_id = #{approvalId}
)

UPDATE `purchase_order`
SET status = #{status}
WHERE id IN (
    SELECT purchase_order_id FROM purchase_order_approval
    WHERE approval_id = #{approvalId}
)
